import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'
import tailwindcss from '@tailwindcss/vite'

export default defineConfig({
  plugins: [react(), tailwindcss()],
})

function App() {
  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50">
      <p className="text-gray-600 text-lg">MKS Loom Portfolio — setup ready</p>
    </div>
  )
}

export default App

const navLinks = [
  { label: 'home', href: '#home' },
  { label: 'About us', href: '#about' },
  { label: 'products', href: '#products' },
  { label: 'certificates', href: '#certificates' },
  { label: 'contact us', href: '#contact' },
]

function Navbar() {
  const scrollTo = (href) => {
    const target = document.querySelector(href)
    target?.scrollIntoView({ behavior: 'smooth' })
  }

  return (
    <header className="relative z-20 w-full px-4 pt-6 sm:px-8 lg:px-12">
      <div className="mx-auto flex max-w-7xl flex-col items-center gap-6 lg:flex-row lg:justify-between">
