          href="#home"
          onClick={(e) => {
            e.preventDefault()
            scrollTo('#home')
          }}
          className="shrink-0 text-left"
        >
          <p className="text-2xl font-semibold tracking-tight text-slate-900 sm:text-3xl">
            MKS Loom
          </p>
          <p className="text-sm text-slate-600">Quality Textile Manufacturing</p>
        </a>

        <nav className="rounded-full bg-slate-900 px-2 py-2 shadow-lg">
