{
  "name": "mks-loom-backend",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "start": "node src/index.js",
    "dev": "node --watch src/index.js"
  },
  "dependencies": {
    "cors": "^2.8.5",
    "dotenv": "^16.4.7",
    "express": "^4.21.2",
    "nodemailer": "^6.10.0"
  }
}

import express from 'express'
import cors from 'cors'
import dotenv from 'dotenv'
import { sendEnquiryEmail } from './mailer.js'

dotenv.config()

const app = express()
const PORT = process.env.PORT || 5000

const allowedOrigins = process.env.CLIENT_ORIGIN
  ? process.env.CLIENT_ORIGIN.split(',').map((origin) => origin.trim())
  : ['http://localhost:5173', 'http://127.0.0.1:5173']

app.use(
  cors({
    origin(origin, callback) {
      if (!origin || allowedOrigins.includes(origin)) {
        callback(null, true)
        return
      }
      callback(new Error('Not allowed by CORS'))
    },
  }),
)
app.use(express.json())

app.get('/api/health', (_req, res) => {
  res.json({ status: 'ok' })
})

app.post('/api/enquiry', async (req, res) => {
  const { fullName, email, phone } = req.body ?? {}

  if (!fullName?.trim() || !email?.trim() || !phone?.trim()) {
    return res.status(400).json({ message: 'Full name, email, and phone number are required.' })
  }

  const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
  if (!emailPattern.test(email.trim())) {
    return res.status(400).json({ message: 'Please enter a valid email address.' })
  }

  const phoneDigits = phone.replace(/\D/g, '')
  if (phoneDigits.length < 10) {
    return res.status(400).json({ message: 'Please enter a valid phone number.' })
  }

  try {
    await sendEnquiryEmail({
      fullName: fullName.trim(),
      email: email.trim(),
      phone: phone.trim(),
    })

    return res.status(200).json({ message: 'Enquiry sent successfully.' })
  } catch (error) {
    console.error('Enquiry email failed:', error)
    return res.status(500).json({ message: 'Unable to send enquiry. Please try again later.' })
  }
})

app.listen(PORT, () => {
  console.log(`Backend running on http://localhost:${PORT}`)
})

import nodemailer from 'nodemailer'

const ADMIN_EMAIL = process.env.ADMIN_EMAIL || 'mkslooms@gmail.com'

function createTransporter() {
  const { SMTP_HOST, SMTP_PORT, SMTP_USER, SMTP_PASS } = process.env

  if (!SMTP_HOST || !SMTP_PORT || !SMTP_USER || !SMTP_PASS) {
    throw new Error('Email service is not configured. Set SMTP variables in backend/.env')
  }

  return nodemailer.createTransport({
    host: SMTP_HOST,
    port: Number(SMTP_PORT),
    secure: Number(SMTP_PORT) === 465,
    auth: {
      user: SMTP_USER,
      pass: SMTP_PASS,
    },
  })
}

export async function sendEnquiryEmail({ fullName, email, phone }) {
  const transporter = createTransporter()

  const html = `
    <h2>New Enquiry — MKS Loom Website</h2>
    <p><strong>Full Name:</strong> ${fullName}</p>
    <p><strong>Email:</strong> ${email}</p>
    <p><strong>Phone:</strong> ${phone}</p>
    <p><em>Submitted from the portfolio enquiry form.</em></p>
  `

  await transporter.sendMail({
    from: `"MKS Loom Website" <${process.env.SMTP_USER}>`,
    to: ADMIN_EMAIL,
    replyTo: email,
    subject: `New Enquiry from ${fullName}`,
    html,
    text: `New Enquiry\n\nFull Name: ${fullName}\nEmail: ${email}\nPhone: ${phone}`,
  })
}

