$phpExe = 'C:\xampp\php\php.exe'

if (-not (Test-Path $phpExe)) {
  $phpCmd = Get-Command php -ErrorAction SilentlyContinue
  if ($phpCmd) {
    $phpExe = $phpCmd.Source
  } else {
    Write-Error 'PHP not found. Install XAMPP or add PHP to your PATH.'
    exit 1
  }
}

Set-Location $PSScriptRoot
Write-Host 'Starting MKS Loom backend at http://localhost:8000'
Write-Host 'API: http://localhost:8000/api/enquiry.php'
Write-Host ''
& $phpExe -S localhost:8000

