import { useState } from 'react'
import logo from '../assets/logo.svg'

const navLinks = [
  { label: 'home', href: '#home' },
  { label: 'About us', href: '#about' },
  { label: 'products', href: '#products' },
  { label: 'certificates', href: '#certificates' },
  { label: 'contact us', href: '#contact' },
]

function Navbar() {
  const [menuOpen, setMenuOpen] = useState(false)
  const [activeLink, setActiveLink] = useState('#home')

  const scrollTo = (href) => {
    const target = document.querySelector(href)
    target?.scrollIntoView({ behavior: 'smooth' })
    setActiveLink(href)
    setMenuOpen(false)
  }

  return (
    <header className="relative z-30 mb-4 w-full px-4 pb-2 pt-4 sm:px-6 sm:pb-3 sm:pt-5 md:mb-0 md:px-8 md:pt-6 lg:px-12">
      <div className="mx-auto grid max-w-7xl grid-cols-[1fr_auto] items-center gap-3 sm:gap-4 md:grid-cols-[1fr_auto_1fr] md:gap-6">
        <a
          href="#home"
          onClick={(e) => {
            e.preventDefault()
            scrollTo('#home')
          }}
          className="flex min-w-0 max-w-[calc(100%-3rem)] items-center gap-2 justify-self-start sm:max-w-none sm:gap-3"
        >
          <img
            src={logo}
            alt="MKS Loom Modernizer logo"
            className="h-9 w-auto shrink-0 object-contain sm:h-10 md:h-11 lg:h-12"
          />
          <span className="min-w-0 font-semibold uppercase leading-[1.15] tracking-wide text-slate-900">
            <span className="block text-[0.625rem] xs:text-[0.7rem] sm:inline sm:text-xs md:text-sm lg:text-base xl:text-lg">
              MKS LOOM
            </span>{' '}
            <span className="block text-[0.625rem] xs:text-[0.7rem] sm:inline sm:text-xs md:text-sm lg:text-base xl:text-lg">
              MODERNIZER
            </span>
          </span>
        </a>

        <nav className="hidden justify-self-center rounded-full bg-slate-900 px-1 py-1 shadow-lg md:block lg:px-1.5 lg:py-1.5">
          <ul className="flex items-center gap-0.5 lg:gap-1">
            {navLinks.map((link) => (
              <li key={link.href}>
                <a
                  href={link.href}
                  onClick={(e) => {
                    e.preventDefault()
                    scrollTo(link.href)
                  }}
                  className={`block rounded-full px-2.5 py-2 text-[0.7rem] font-medium leading-none transition-colors md:px-3 md:py-2.5 md:text-xs lg:px-4 lg:py-2.5 lg:text-sm xl:px-5 xl:text-base ${
                    activeLink === link.href
                      ? 'bg-white text-slate-900'
                      : 'text-white hover:text-emerald-200'
                  }`}
                >
                  {link.label}
                </a>
              </li>
            ))}
          </ul>
        </nav>

        <div className="flex h-10 items-center justify-self-end sm:h-11 md:h-12">
          <button
            type="button"
            onClick={() => setMenuOpen((open) => !open)}
            className="inline-flex h-10 w-10 items-center justify-center rounded-full bg-slate-900 text-white md:hidden"
            aria-expanded={menuOpen}
            aria-label={menuOpen ? 'Close menu' : 'Open menu'}
          >
            {menuOpen ? (
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="h-5 w-5">
                <path
                  fillRule="evenodd"
                  d="M5.47 5.47a.75.75 0 0 1 1.06 0L12 10.94l5.47-5.47a.75.75 0 1 1 1.06 1.06L13.06 12l5.47 5.47a.75.75 0 1 1-1.06 1.06L12 13.06l-5.47 5.47a.75.75 0 1 1-1.06-1.06L10.94 12 5.47 6.53a.75.75 0 0 1 0-1.06Z"
                  clipRule="evenodd"
                />
              </svg>
            ) : (
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="h-5 w-5">
                <path
                  fillRule="evenodd"
                  d="M3 6.75A.75.75 0 0 1 3.75 6h16.5a.75.75 0 0 1 0 1.5H3.75A.75.75 0 0 1 3 6.75ZM3 12a.75.75 0 0 1 .75-.75h16.5a.75.75 0 0 1 0 1.5H3.75A.75.75 0 0 1 3 12Zm0 5.25a.75.75 0 0 1 .75-.75h16.5a.75.75 0 0 1 0 1.5H3.75a.75.75 0 0 1-.75-.75Z"
                  clipRule="evenodd"
                />
              </svg>
            )}
          </button>
        </div>
      </div>

      {menuOpen && (
        <nav className="mx-auto mt-3 max-w-7xl rounded-2xl bg-slate-900 p-3 shadow-lg md:hidden">
          <ul className="flex flex-col gap-1">
            {navLinks.map((link) => (
              <li key={link.href}>
                <a
                  href={link.href}
                  onClick={(e) => {
                    e.preventDefault()
                    scrollTo(link.href)
                  }}
                  className={`block rounded-xl px-4 py-3 text-sm font-medium transition-colors sm:text-base ${
                    activeLink === link.href
                      ? 'bg-white text-slate-900'
                      : 'text-white hover:bg-white/10'
                  }`}
                >
                  {link.label}
                </a>
              </li>
            ))}
          </ul>
        </nav>
      )}
    </header>
  )
}

export default Navbar

