import { useState } from 'react'
import logo from '../assets/logo.svg'

const navLinks = [
  { label: 'HOME', href: '#home', uppercase: true },
  { label: 'About us', href: '#about', uppercase: true },
  { label: 'products', href: '#products', uppercase: true },
  { label: 'certificates', href: '#certificates', uppercase: true },
  { label: 'Contact', href: '#contact', uppercase: false },
]

function NavLink({ link, isActive, onClick, className = '' }) {
  return (
    <a
      href={link.href}
      onClick={onClick}
      className={`relative pb-1 text-xs font-medium tracking-wide transition-colors sm:text-sm lg:text-[0.9rem] ${
        link.uppercase ? 'uppercase' : ''
      } ${
        isActive
          ? 'text-slate-900 after:absolute after:bottom-0 after:left-0 after:h-[2px] after:w-full after:bg-slate-900'
          : 'text-slate-500 hover:text-slate-900'
      } ${className}`}
    >
      {link.uppercase ? link.label.toUpperCase() : link.label}
    </a>
  )
}

function Navbar() {
  const [menuOpen, setMenuOpen] = useState(false)
  const [activeLink, setActiveLink] = useState('#home')

  const scrollTo = (href) => {
    const target = document.querySelector(href)
    target?.scrollIntoView({ behavior: 'smooth' })
    setActiveLink(href)
    setMenuOpen(false)
  }

  const handleNavClick = (href) => (e) => {
    e.preventDefault()
    scrollTo(href)
  }

  return (
    <header className="relative z-30 w-full px-4 pb-2 pt-4 sm:px-6 sm:pb-3 sm:pt-5 md:px-8 md:pt-6 lg:px-12">
      <div className="mx-auto max-w-7xl rounded-2xl bg-white px-4 py-3 shadow-[0_4px_24px_rgba(15,23,42,0.08)] ring-1 ring-slate-900/5 sm:rounded-[1.75rem] sm:px-6 sm:py-4 lg:px-8">
        <div className="flex items-center justify-between gap-4">
          <a
            href="#home"
            onClick={handleNavClick('#home')}
            className="flex min-w-0 items-center gap-2 sm:gap-3"
          >
            <img
              src={logo}
              alt="MKS Loom Modernizer logo"
              className="h-8 w-auto shrink-0 object-contain sm:h-9 md:h-10 lg:h-11"
            />
            <span className="whitespace-nowrap text-[0.6rem] font-bold uppercase leading-none tracking-wide text-slate-900 xs:text-[0.65rem] sm:text-xs md:text-sm lg:text-base">
              MKS LOOM MODERNIZER
            </span>
          </a>

          <nav className="hidden items-center gap-5 md:flex lg:gap-8 xl:gap-10">
            {navLinks.map((link) => (
              <NavLink
                key={link.href}
                link={link}
                isActive={activeLink === link.href}
                onClick={handleNavClick(link.href)}
              />
            ))}
          </nav>

          <button
            type="button"
            onClick={() => setMenuOpen((open) => !open)}
            className="inline-flex h-9 w-9 shrink-0 items-center justify-center rounded-lg text-slate-900 transition hover:bg-slate-100 md:hidden"
            aria-expanded={menuOpen}
            aria-label={menuOpen ? 'Close menu' : 'Open menu'}
          >
            {menuOpen ? (
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="h-6 w-6">
                <path
                  fillRule="evenodd"
                  d="M5.47 5.47a.75.75 0 0 1 1.06 0L12 10.94l5.47-5.47a.75.75 0 1 1 1.06 1.06L13.06 12l5.47 5.47a.75.75 0 1 1-1.06 1.06L12 13.06l-5.47 5.47a.75.75 0 1 1-1.06-1.06L10.94 12 5.47 6.53a.75.75 0 0 1 0-1.06Z"
                  clipRule="evenodd"
                />
              </svg>
            ) : (
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="currentColor" className="h-6 w-6">
