const navLinks = [
  { label: 'HOME', href: '#home', uppercase: true },
  { label: 'About us', href: '#about', uppercase: true },
  { label: 'certificates', href: '#certificates', uppercase: true },
  { label: 'Contact', href: '#contact', uppercase: false },
]

function NavLink({ link, isActive, onClick, className = '' }) {
  return (
    <a
      href={link.href}
      onClick={onClick}
      className={`relative pb-0.5 text-xs font-normal tracking-wide transition-colors sm:text-sm lg:text-[.9rem] ${
        link.uppercase ? 'uppercase' : ''
      } ${
        isActive
          ? 'text-slate-900 after:absolute after:bottom-0 after:left-0 after:h-[2px] after:w-full after:bg-slate-900'
          : 'text-slate-500 hover:text-slate-900'
      } ${className}`}
    >
      {link.uppercase ? link.label.toUpperCase() : link.label}
    </a>
  )
}

function ProductsDropdown({ isActive, onSelect, onClose }) {
  const [open, setOpen] = useState(false)
  const dropdownRef = useRef(null)

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setOpen(false)
      }
    }

    if (open) {
      document.addEventListener('mousedown', handleClickOutside)
    }

    return () => document.removeEventListener('mousedown', handleClickOutside)
  }, [open])

  const handleProductClick = (productId) => {
    navigateToProduct(productId)
    onSelect()
    setOpen(false)
    onClose?.()
  }

  const handleViewAll = () => {
    navigateToProductsSection()
    onSelect()
    setOpen(false)
    onClose?.()
  }

  return (
    <div ref={dropdownRef} className="relative">
      <button
        type="button"
        onClick={() => setOpen((current) => !current)}
        className={`relative inline-flex items-center gap-1 pb-0.5 text-xs font-normal uppercase tracking-wide transition-colors sm:text-sm lg:text-[.9rem] ${
