import { useEffect, useState } from 'react'

function TypingText({
  text,
  typingSpeed = 120,
  deletingSpeed = 80,
  pauseMs = 1500,
}) {
  const [displayed, setDisplayed] = useState('')
  const [isDeleting, setIsDeleting] = useState(false)

  useEffect(() => {
    let timeoutId

    if (!isDeleting && displayed.length < text.length) {
      timeoutId = setTimeout(() => {
        setDisplayed(text.slice(0, displayed.length + 1))
      }, typingSpeed)
    } else if (!isDeleting && displayed.length === text.length) {
      timeoutId = setTimeout(() => setIsDeleting(true), pauseMs)
    } else if (isDeleting && displayed.length > 0) {
      timeoutId = setTimeout(() => {
        setDisplayed(text.slice(0, displayed.length - 1))
      }, deletingSpeed)
    } else {
      timeoutId = setTimeout(() => setIsDeleting(false), 400)
    }

    return () => clearTimeout(timeoutId)
  }, [displayed, isDeleting, text, typingSpeed, deletingSpeed, pauseMs])

  return (
    <>
      {displayed}
      <span className="ml-0.5 inline-block w-[2px] animate-pulse text-slate-900">|</span>
    </>
  )
}

export default TypingText

