}

function Products() {
  const [selectedProduct, setSelectedProduct] = useState(null)

  const handleQuery = () => {
    setSelectedProduct(null)
    scrollToContact()
  }

  useEffect(() => {
    const handleSelectProduct = (event) => {
      const { productId, index } = event.detail ?? {}
      let product = null

      if (productId) {
        product = products.find((item) => item.id === productId)
      } else if (typeof index === 'number' && index >= 0 && index < products.length) {
        product = products[index]
      }

      if (product) setSelectedProduct(product)
    }

    window.addEventListener('mks-select-product', handleSelectProduct)
    return () => window.removeEventListener('mks-select-product', handleSelectProduct)
  }, [])

  return (
    <section
      id="products"
      className="bg-slate-50 px-4 py-14 sm:px-6 sm:py-16 md:px-8 md:py-20 lg:px-12 lg:py-24"
    >
      <div className="mx-auto max-w-7xl">
        <div className="max-w-2xl">
          <p className="text-sm font-medium text-slate-500 sm:text-base">Our products</p>
          <h2 className="mt-3 text-3xl font-semibold leading-tight tracking-tight text-slate-900 sm:text-4xl lg:text-[2.75rem]">
            Woven With Precision
          </h2>
          <p className="mt-4 text-sm leading-relaxed text-slate-600 sm:text-base lg:text-lg">
            Explore our core product offerings. For additional models, specifications, or bulk
            orders, reach out through our enquiry form.
          </p>
        </div>

        <div className="mt-10 grid gap-6 sm:mt-12 sm:gap-8 md:grid-cols-2 lg:grid-cols-3">
          {products.map((product) => (
            <ProductCard
              key={product.id}
              product={product}
              onViewDetails={setSelectedProduct}
            />
          ))}
        </div>

        <div className="mt-10 rounded-2xl bg-white px-5 py-6 text-center shadow-sm ring-1 ring-slate-900/5 sm:mt-12 sm:rounded-3xl sm:px-8 sm:py-8">
          <p className="text-base font-medium text-slate-900 sm:text-lg">
            Looking for more product options?
          </p>
          <p className="mt-2 text-sm text-slate-600 sm:text-base">
            Share your requirements and our team will assist you with the full catalogue.
          </p>
          <button
            type="button"
            onClick={scrollToContact}
            className="mt-5 inline-flex items-center justify-center rounded-full bg-emerald-600 px-6 py-3 text-sm font-medium text-white transition hover:bg-emerald-700 sm:text-base"
          >
            Go to enquiry form
          </button>
        </div>
      </div>

      {selectedProduct && (
        <ProductModal
          product={selectedProduct}
          onClose={() => setSelectedProduct(null)}
          onQuery={handleQuery}
        />
      )}
    </section>
  )
}

export default Products

