import { useEffect, useState } from 'react'

function HeroCarousel({ slides, intervalMs = 5000 }) {
  const [activeIndex, setActiveIndex] = useState(0)

  useEffect(() => {
    if (slides.length <= 1) return undefined

    const timerId = setInterval(() => {
      setActiveIndex((current) => (current === slides.length - 1 ? 0 : current + 1))
    }, intervalMs)

    return () => clearInterval(timerId)
  }, [slides.length, intervalMs])

  const goToSlide = (index) => {
    setActiveIndex(index)
  }

  const goPrev = () => {
    setActiveIndex((current) => (current === 0 ? slides.length - 1 : current - 1))
  }

  const goNext = () => {
    setActiveIndex((current) => (current === slides.length - 1 ? 0 : current + 1))
  }

  return (
    <div className="relative mx-auto mt-8 max-w-5xl sm:mt-12 md:mt-16 lg:mt-20">
      <div className="rounded-2xl bg-emerald-600 p-2 shadow-2xl sm:rounded-3xl sm:p-3 md:p-4">
        <div className="relative overflow-hidden rounded-xl border-2 border-white/90 sm:rounded-2xl md:rounded-3xl">
          <div className="relative aspect-[4/3] w-full sm:aspect-[16/10] md:aspect-[16/9]">
            {slides.map((slide, index) => (
              <img
                key={slide.alt}
                src={slide.src}
                alt={slide.alt}
                className={`absolute inset-0 h-full w-full object-cover transition-opacity duration-700 ease-in-out ${
                  index === activeIndex ? 'opacity-100' : 'opacity-0'
                }`}
              />
            ))}
          </div>

          {slides.length > 1 && (
            <>
              <button
                type="button"
                onClick={goPrev}
                className="absolute left-3 top-1/2 z-10 hidden -translate-y-1/2 rounded-full bg-white/90 p-2 text-slate-900 shadow-md ring-1 ring-slate-900/10 transition hover:bg-white sm:inline-flex"
                aria-label="Previous slide"
              >
                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="h-5 w-5">
                  <path
                    fillRule="evenodd"
                    d="M11.78 5.22a.75.75 0 0 1 0 1.06L8.06 10l3.72 3.72a.75.75 0 1 1-1.06 1.06l-4.25-4.25a.75.75 0 0 1 0-1.06l4.25-4.25a.75.75 0 0 1 1.06 0Z"
                    clipRule="evenodd"
                  />
                </svg>
              </button>

              <button
                type="button"
                onClick={goNext}
                className="absolute right-3 top-1/2 z-10 hidden -translate-y-1/2 rounded-full bg-white/90 p-2 text-slate-900 shadow-md ring-1 ring-slate-900/10 transition hover:bg-white sm:inline-flex"
                aria-label="Next slide"
              >
                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="h-5 w-5">
                  <path
                    fillRule="evenodd"
                    d="M8.22 5.22a.75.75 0 0 1 1.06 0l4.25 4.25a.75.75 0 0 1 0 1.06l-4.25 4.25a.75.75 0 1 1-1.06-1.06L11.94 10 8.22 6.28a.75.75 0 0 1 0-1.06Z"
                    clipRule="evenodd"
                  />
                </svg>
              </button>
            </>
          )}
        </div>

        {slides.length > 1 && (
          <div className="mt-3 flex items-center justify-center gap-2 sm:mt-4">
            {slides.map((slide, index) => (
              <button
                key={slide.alt}
                type="button"
                onClick={() => goToSlide(index)}
                className={`rounded-full transition-all ${
                  activeIndex === index
                    ? 'h-2.5 w-8 bg-white'
                    : 'h-2.5 w-2.5 bg-white/50 hover:bg-white/70'
                }`}
                aria-label={`Go to slide ${index + 1}`}
              />
            ))}
          </div>
        )}
      </div>

      <div className="pointer-events-none absolute -bottom-4 left-1/2 h-8 w-[85%] -translate-x-1/2 rounded-full bg-emerald-900/20 blur-2xl sm:-bottom-6 sm:h-12 sm:w-[90%]" />
    </div>
  )
}

